class UserRegistration {
  register(data: unknown): void {
    const input = JSON.parse(data as string);

    if (!input.email?.includes('@')) throw new Error('Invalid email');
    if (input.password.length < 8) throw new Error('Too short');

    db.query('INSERT INTO users VALUES (?)', [input]);

    sendEmail(input.email, 'Welcome!');
    logger.info(`Registered: ${input.email}`);
  }
}

class OrderProcessor {
  process(order: Order): void {
    if (order.items.length === 0) throw new Error('Empty order');

    db.run('INSERT INTO orders ...', [order]);
    db.run('UPDATE inventory ...', [order.items]);

    sendgrid.send({
      to: order.customer.email,
      subject: 'Order confirmed',
    });
  }
}

